package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Execute the ping command directly. Using exec.Command with separate arguments
	// is more secure than using bash -c with fmt.Sprintf, as it prevents shell injection.
	// -c specifies the number of packets to send (standard on Linux and macOS).
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		// If ping fails (e.g., host unreachable or command not found), return the error and output.
		return 0, fmt.Errorf("ping execution failed: %w (output: %s)", err, strings.TrimSpace(string(output)))
	}

	outputStr := string(output)
	// Look for the line containing RTT statistics (min/avg/max).
	// Linux format: rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
	// macOS format: round-trip min/avg/max/stddev = 12.345/23.456/34.567/5.678 ms
	lines := strings.Split(outputStr, "\n")
	var statsLine string
	for _, line := range lines {
		if strings.Contains(line, "min/avg/max") {
			statsLine = line
			break
		}
	}

	if statsLine == "" {
		return 0, errors.New("could not find RTT statistics in ping output")
	}

	// Regex to extract the average latency.
	// We look for the pattern of four numbers separated by slashes.
	// The average is the second number in the sequence (index 2 in matches).
	re := regexp.MustCompile(`([0-9.]+)/([0-9.]+)/([0-9.]+)/([0-9.]+)`)
	matches := re.FindStringSubmatch(statsLine)
	if len(matches) < 3 {
		return 0, errors.New("failed to parse average latency from statistics line")
	}

	// matches[2] corresponds to the second capture group (avg).
	avgStr := matches[2]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency '%s' to float: %w", avgStr, err)
	}

	return avg, nil
}

func main() {
	// Example usage of the MeasureLatency function.
	host := "8.8.8.8"
	count := 3

	fmt.Printf("Measuring latency to %s (%d attempts)...\n", host, count)
	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}

	fmt.Printf("Average Latency: %.3f ms\n", avg)
}

