package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Security Fix: Prevent argument injection by ensuring the host doesn't start with a hyphen.
	// While exec.Command handles arguments safely, some binaries might interpret leading hyphens 
	// in the host argument as flags if not handled carefully.
	if strings.HasPrefix(strings.TrimSpace(host), "-") {
		return 0, errors.New("invalid host: host cannot start with a hyphen")
	}

	// Security Fix: Execute the 'ping' command directly without using a shell (bash -c).
	// By passing arguments as a slice to exec.Command, we avoid command injection vulnerabilities.
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, string(output))
	}

	outputStr := string(output)

	// Regex to extract RTT statistics from the ping output.
	// This regex handles both Linux ('rtt') and macOS ('round-trip') output formats.
	// Format: rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
	re := regexp.MustCompile(`(?:rtt|round-trip) min/avg/max/(?:mdev|stddev) = ([\d.]+)/([\d.]+)/([\d.]+)/([\d.]+)`)
	matches := re.FindStringSubmatch(outputStr)

	if len(matches) < 3 {
		return 0, errors.New("could not find or parse RTT statistics in ping output")
	}

	// matches[2] corresponds to the 'avg' value in the min/avg/max/mdev sequence.
	avgStr := matches[2]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}

	return avg, nil
}

func main() {
	// Example usage
	host := "8.8.8.8"
	count := 3
	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}
	fmt.Printf("Average latency for %s: %.3f ms\n", host, avg)
}

