package main

import (
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
)

// MeasureLatency executes the system's ping command to calculate the average round-trip time.
// It returns the average latency in milliseconds.
// 
// Parameters:
//   - host: The target hostname or IP address (e.g., "google.com" or "8.8.8.8").
//   - count: The number of ping packets to send.
//
// Returns:
//   - float64: The average latency in milliseconds.
//   - error: An error if the command fails or the output cannot be parsed.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("ping count must be greater than zero")
	}

	var cmd *exec.Cmd

	// Configure the ping command based on the operating system.
	// Windows uses '-n' for the number of packets, while Unix-like systems (Linux, macOS) use '-c'.
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	// CombinedOutput runs the command and returns its combined standard output and standard error.
	out, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w (output: %s)", err, string(out))
	}

	output := string(out)

	// Regex for Unix-like systems (Linux, macOS, BSD).
