// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// SECURITY FIX: Validate the host input to prevent argument injection.
	// This ensures the host string only contains characters valid for a hostname or IP address.
	// It specifically prevents leading dashes (which could be interpreted as flags) or shell metacharacters.
	validHost := regexp.MustCompile(`^[a-zA-Z0-9.-]+$`)
	if !validHost.MatchString(host) {
		return 0, errors.New("invalid host format")
	}

	// SECURITY FIX: Avoid using 'bash -c' or any shell to execute the command.
	// By passing arguments directly to exec.Command, the OS treats them as literal strings,
	// effectively neutralizing command injection attacks.
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, string(output))
	}

	// Look for the line containing RTT statistics
	outputStr := string(output)
	lines := strings.Split(outputStr, "\n")
	var statsLine string
	for _, line := range lines {
		// Matches both Linux "rtt min/avg/max" and macOS "round-trip min/avg/max"
		if strings.Contains(line, "min/avg/max") {
			statsLine = line
			break
		}
	}

	if statsLine == "" {
		return 0, errors.New("could not find RTT statistics in ping output")
	}

	// Extract average latency using a flexible regex.
	// Example line: rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
	// The average is the second value in the slash-separated sequence.
	re := regexp.MustCompile(`= [0-9.]+/([0-9.]+)/[0-9.]+/[0-9.]+`)
	matches := re.FindStringSubmatch(statsLine)
	if len(matches) < 2 {
		return 0, errors.New("failed to parse average latency from ping output")
	}

	avgStr := matches[1]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}

	return avg, nil
}

func main() {
	// Example usage
	host := "google.com"
	count := 3
	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}
	fmt.Printf("Average latency for %s over %d attempts: %.3f ms\n", host, count, avg)
}

