package main

import (
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency executes the system ping command to calculate the average latency to a host.
// It uses the os/exec package to run the command and parses the output for the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be greater than 0")
	}

	var cmd *exec.Cmd
	// Determine the operating system to set the correct ping flags.
	// Unix-like systems use '-c' for count, while Windows uses '-n'.
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	// Execute the command and capture combined output (stdout and stderr).
	out, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w (output: %s)", err, string(out))
	}

	outputStr := string(out)

	// Parsing logic for Unix-like systems (Linux/macOS)
	// Example: rtt min/avg/max/mdev = 12.103/13.452/15.001/0.123 ms
	unixRegex := regexp.MustCompile(`(?:rtt|round-trip)\s+min/avg/max/(?:mdev|stddev)\s+=\s+([0-9.]+)/([0-9.]+)/([0-9.]+)/([0-9.]+)`)
	unixMatches := unixRegex.FindStringSubmatch(outputStr)
	if len(unixMatches) >= 3 {
		// unixMatches[2] is the 'avg' value
		avg, err := strconv.ParseFloat(unixMatches[2], 64)
		if err != nil {
			return 0, fmt.Errorf("failed to parse average latency from unix output: %w", err)
		}
		return avg, nil
	}

	// Parsing logic for Windows
	// Example: Average = 14ms
	if runtime.GOOS == "windows" {
		winRegex := regexp.MustCompile(`Average\s+=\s+(\d+)ms`)
		winMatches := winRegex.FindStringSubmatch(outputStr)
		if len(winMatches) >= 2 {
			avg, err := strconv.ParseFloat(winMatches[1], 64)
			if err != nil {
				return 0, fmt.Errorf("failed to parse average latency from windows output: %w", err)
			}
			return avg, nil
		}
	}

	// If no regex matched, return an error.
	return 0, fmt.Errorf("could not parse average latency from ping output")
}

func main() {
	// Configuration
	targetHost := "8.8.8.8"
	pingCount := 4

	fmt.Printf("Measuring latency to %s with %d packets...\n", targetHost, pingCount)

	avgLatency, err := MeasureLatency(targetHost, pingCount)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}

	fmt.Printf("Ping successful.\n")
	fmt.Printf("Average Latency: %.3f ms\n", avgLatency)
}

