package main

import (
	"fmt"
	"os"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
)

// MeasureLatency executes the system's ping command to measure network latency.
// It returns the average latency in milliseconds or an error if the execution or parsing fails.
// This implementation supports both Windows and Unix-like (Linux/macOS) systems.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be greater than 0")
	}

	var cmd *exec.Cmd
	if runtime.GOOS == "windows" {
		// Windows uses -n for the number of echo requests
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		// Unix-like systems (Linux, macOS) use -c for the packet count
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
		// Set LC_ALL=C to ensure the output format is in English for consistent parsing
		cmd.Env = append(os.Environ(), "LC_ALL=C")
	}

	// CombinedOutput runs the command and returns its combined standard output and standard error.
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w (output: %s)", err, string(output))
	}

	outStr := string(output)
	var avg float64

	if runtime.GOOS == "windows" {
		// Example Windows output: "... Average = 15ms"
		re := regexp.MustCompile(`Average\s*=\s*(\d+)\s*ms`)
		matches := re.FindStringSubmatch(outStr)
		if len(matches) < 2 {
			return 0, fmt.Errorf("failed to parse average latency from Windows ping output")
		}
		avg, err = strconv.ParseFloat(matches[1], 64)
	} else {
		// Example Unix output: "round-trip min/avg/max/stddev = 14.234/15.123/16.012/0.821 ms"
		// The regex looks for the slash-separated values after the '=' sign.
		// We capture the second group which corresponds to the 'avg' value.
		re := regexp.MustCompile(`=\s*([\d.]+)/([\d.]+)/([\d.]+)`)
		matches := re.FindStringSubmatch(outStr)
		if len(matches) < 3 {
			return 0, fmt.Errorf("failed to parse average latency from Unix ping output")
		}
		avg, err = strconv.ParseFloat(matches[2], 64)
	}

	if err != nil {
		return 0, fmt.Errorf("failed to convert latency string to float: %w", err)
	}

	return avg, nil
}

func main() {
	// Example configuration
	targetHost := "8.8.8.8"
	pingCount := 4

	fmt.Printf("Measuring latency to %s with %d attempts...\n", targetHost, pingCount)

	avgLatency, err := MeasureLatency(targetHost, pingCount)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Average Latency: %.3f ms\n", avgLatency)
}

