package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Execute ping command directly without a shell to avoid injection vulnerabilities.
	// -c specifies the number of packets to send (Linux/macOS).
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w (output: %s)", err, string(output))
	}

	// Use a regex to extract the RTT statistics line.
	// This pattern handles both Linux ("rtt min/avg/max/mdev") and macOS ("round-trip min/avg/max/stddev").
	// It captures the four numeric values: min, avg, max, and the deviation.
	re := regexp.MustCompile(`(?:rtt|round-trip) min/avg/max/(?:mdev|stddev) = ([0-9.]+)/([0-9.]+)/([0-9.]+)/([0-9.]+)`)
	matches := re.FindStringSubmatch(string(output))

	// matches[0] is the full string, [1] is min, [2] is avg, [3] is max, [4] is mdev/stddev.
	if len(matches) < 3 {
		return 0, errors.New("could not find RTT statistics in ping output")
	}

	// Extract the average latency (the second capture group).
	avgStr := matches[2]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency '%s' to float: %w", avgStr, err)
	}

	return avg, nil
}

func main() {
	// Example usage
	host := "8.8.8.8"
	count := 4
	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}

	fmt.Printf("Average latency for %s: %.3f ms\n", host, avg)
}

