package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	// Basic input validation
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Security Fix: Prevent argument injection. 
	// By ensuring the host doesn't start with a hyphen, we prevent it from being 
	// interpreted as a command-line flag by the ping utility.
	trimmedHost := strings.TrimSpace(host)
	if strings.HasPrefix(trimmedHost, "-") {
		return 0, errors.New("invalid host name")
	}

	// Security Fix: Avoid using 'bash -c' or any shell to execute the command.
	// By passing arguments directly to exec.Command, we prevent shell injection.
	// The 'host' and 'count' variables are passed as distinct arguments to the executable.
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), trimmedHost)

	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, string(output))
	}

	outputStr := string(output)

	// Extract average latency using regex.
	// Linux/iputils ping output format: rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
	// We use [0-9.]+ to handle both integer and decimal values across different environments.
	re := regexp.MustCompile(`rtt min/avg/max/mdev = [0-9.]+/([0-9.]+)/[0-9.]+/[0-9.]+ ms`)
	matches := re.FindStringSubmatch(outputStr)
	if len(matches) < 2 {
		return 0, errors.New("failed to parse average latency from ping output")
	}

	// matches[1] is the first capture group: ([0-9.]+)
	avgStr := matches[1]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}

	return avg, nil
}

func main() {
	// Example usage:
	host := "8.8.8.8"
	count := 3
	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}
	fmt.Printf("Average Latency for %s: %.3f ms\n", host, avg)
}

