package main

import (
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
)

// MeasureLatency executes the system ping command to measure the average network latency
// to a specified host over a defined number of attempts.
// It returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("ping count must be greater than 0")
	}

	var cmd *exec.Cmd
	// Determine the operating system to set the appropriate ping flags.
	// Windows uses '-n' for the number of packets, while Unix-like systems use '-c'.
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	// Run the command and capture combined stdout and stderr.
	out, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w (output: %s)", err, string(out))
	}

	output := string(out)

	// Regex for Unix-like systems (Linux, macOS, etc.)
	// Usually looks like: rtt min/avg/max/mdev = 12.345/15.678/18.910/1.234 ms
	// We capture the second value (avg).
	unixRegex := regexp.MustCompile(`min/avg/max/.*?=\s*[0-9.]+/([0-9.]+)/`)
	if matches := unixRegex.FindStringSubmatch(output); len(matches) >= 2 {
		return strconv.ParseFloat(matches[1], 64)
	}

	// Regex for Windows systems
	// Usually looks like: Average = 15ms
	winRegex := regexp.MustCompile(`Average\s*=\s*(\d+)ms`)
	if matches := winRegex.FindStringSubmatch(output); len(matches) >= 2 {
		return strconv.ParseFloat(matches[1], 64)
	}

	return 0, fmt.Errorf("failed to parse average latency from ping output")
}

func main() {
	// Example usage
	host := "8.8.8.8"
	count := 4

	fmt.Printf("Pinging %s %d times...\n", host, count)
	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}

	fmt.Printf("Average Latency: %.3f ms\n", avgLatency)
}

