import (
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
)

// MeasureLatency pings a specified host a user-defined number of times
// and returns the average latency in milliseconds.
// It uses the system's native ping command via the os/exec package.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}
	if count <= 0 {
		return 0, fmt.Errorf("count must be greater than 0")
	}

	var cmd *exec.Cmd
	// Configure the ping command based on the operating system.
	// Windows uses '-n' for count, while Linux/macOS use '-c'.
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	// CombinedOutput runs the command and returns its combined standard output and standard error.
	out, err := cmd.CombinedOutput()
	output := string(out)
	if err != nil {
		return 0, fmt.Errorf("ping execution failed: %w (output: %s)", err, output)
	}

	// Parse the output to extract the average latency.
	// Ping output formats vary significantly between Windows and Unix-like systems.
	if runtime.GOOS == "windows" {
		// Windows example: "Minimum = 11ms, Maximum = 15ms, Average = 13ms"
		re := regexp.MustCompile(`Average = (\d+)\s*ms`)
		matches := re.FindStringSubmatch(output)
		if len(matches) > 1 {
			return strconv.ParseFloat(matches[1], 64)
		}
	} else {
		// Unix/macOS example: "min/avg/max/mdev = 1.234/2.345/3.456/0.456 ms"
		// We target the summary line and extract the second value (the average).
		re := regexp.MustCompile(`min/avg/max/.*? = ([0-9.]+)/([0-9.]+)/([0-9.]+)`)
		matches := re.FindStringSubmatch(output)
		if len(matches) > 2 {
			// matches[2] is the capture group for the 'avg' value.
			return strconv.ParseFloat(matches[2], 64)
		}
	}

	return 0, fmt.Errorf("failed to parse average latency from ping output")
}

func main() {
	// Example configuration
	targetHost := "8.8.8.8"
	pingCount := 4

	fmt.Printf("Starting latency measurement for host: %s (count: %d)...\n", targetHost, pingCount)

	avgLatency, err := MeasureLatency(targetHost, pingCount)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}

	fmt.Printf("Measurement complete.\n")
	fmt.Printf("Average Latency: %.3f ms\n", avgLatency)
}

