package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
// This implementation is designed for Unix-like systems (Linux, macOS).
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Use the 'ping' command with the '-c' flag for count.
	// Arguments are passed directly to exec.Command to prevent shell injection.
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w (output: %s)", err, strings.TrimSpace(string(output)))
	}

	outputStr := string(output)

	// Look for the line containing RTT statistics.
	// Linux: rtt min/avg/max/mdev = 12.345/13.456/14.567/0.123 ms
	// macOS: round-trip min/avg/max/stddev = 12.345/13.456/14.567/0.123 ms
	var statsLine string
	lines := strings.Split(outputStr, "\n")
	for _, line := range lines {
		if strings.Contains(line, "min/avg/max") {
			statsLine = line
			break
		}
	}

	if statsLine == "" {
		return 0, errors.New("could not find RTT statistics in ping output")
	}

	// Regex to capture the slash-separated values (min/avg/max/mdev).
	// We capture the second group which corresponds to the average.
	re := regexp.MustCompile(`([0-9.]+)/([0-9.]+)/([0-9.]+)/([0-9.]+)`)
	matches := re.FindStringSubmatch(statsLine)

	// matches[0] is the full match, matches[1] is min, matches[2] is avg.
	if len(matches) < 3 {
		return 0, errors.New("failed to parse average latency from ping output")
	}

	avgStr := matches[2]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency '%s' to float: %w", avgStr, err)
	}

	return avg, nil
}

func main() {
	// Example usage
	host := "8.8.8.8"
	count := 4

	fmt.Printf("Measuring average latency to %s using %d pings...\n", host, count)
	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}

	fmt.Printf("Average Latency: %.3f ms\n", avg)
}

