package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

// hostRegex validates that the host is a valid-looking hostname or IP address.
// This prevents passing command flags or shell-sensitive characters.
var hostRegex = regexp.MustCompile(`^[a-zA-Z0-9.-]+$`)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec safely and parses the output.
func MeasureLatency(host string, count int) (float64, error) {
	// 1. Basic validation
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}
	if count > 100 {
		return 0, errors.New("count too high: please limit to 100 or fewer")
	}

	// 2. Strict host validation to prevent command injection or flag injection
	if !hostRegex.MatchString(host) {
		return 0, errors.New("invalid host format")
	}

	// 3. Execute command directly without a shell (bash -c)
	// This prevents command injection as arguments are passed directly to the syscall.
	// We use strconv.Itoa for the count to ensure it's treated as a single string argument.
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, string(output))
	}

	// 4. Parse the output
	outputStr := string(output)
	lines := strings.Split(outputStr, "\n")
	var statsLine string
	for _, line := range lines {
		// Matches both "rtt min/avg/max/mdev" (Linux) and "round-trip min/avg/max/stddev" (macOS)
		if strings.Contains(line, "min/avg/max") {
			statsLine = line
			break
		}
	}

	if statsLine == "" {
		return 0, errors.New("could not find RTT statistics in ping output")
	}

	// 5. Extract average latency using a flexible regex
	// Example line: rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
	// We look for the second numerical value in the slash-separated sequence.
	re := regexp.MustCompile(`= [0-9.]+[/]([0-9.]+)[/][0-9.]+[/][0-9.]+`)
	matches := re.FindStringSubmatch(statsLine)
	if len(matches) < 2 {
		return 0, errors.New("failed to parse average latency from ping output")
	}

	avgStr := matches[1]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}

	return avg, nil
}

func main() {
	// Example usage
	avg, err := MeasureLatency("8.8.8.8", 3)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}
	fmt.Printf("Average Latency: %.3f ms\n", avg)
}

