package main

import (
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
)

// MeasureLatency pings a specified host a user-defined number of times
// and returns the average latency in milliseconds.
// It uses the system's 'ping' command via the os/exec package.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}
	if count <= 0 {
		return 0, fmt.Errorf("count must be greater than 0")
	}

	var cmd *exec.Cmd
	// Windows uses '-n' for count, while Linux/macOS (Unix-like) uses '-c'.
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		// On Unix-like systems, we use -c for count.
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	// CombinedOutput runs the command and returns its combined standard output and standard error.
	out, err := cmd.CombinedOutput()
	output := string(out)

	// If the command fails to execute entirely (e.g., ping not found).
	if err != nil && len(output) == 0 {
		return 0, fmt.Errorf("ping command failed to execute: %w", err)
	}

	// Parsing logic varies based on the operating system's ping output format.
	if runtime.GOOS == "windows" {
		// Expected Windows output snippet: "Average = 12ms" or "Average = 12 ms"
		re := regexp.MustCompile(`Average = (\d+)\s*ms`)
		matches := re.FindStringSubmatch(output)
		if len(matches) >= 2 {
			return strconv.ParseFloat(matches[1], 64)
		}
	} else {
		// Expected Unix (Linux/macOS) output snippet: 
		// "rtt min/avg/max/mdev = 1.234/2.345/3.456/0.456 ms"
		// The second value in the sequence is the average.
		re := regexp.MustCompile(`([0-9.]+)/([0-9.]+)/([0-9.]+)/([0-9.]+)\s+ms`)
		matches := re.FindStringSubmatch(output)
		if len(matches) >= 3 {
			// matches[1] is min, matches[2] is avg, matches[3] is max
			return strconv.ParseFloat(matches[2], 64)
		}
	}

	// If parsing fails, provide the error and the output for debugging.
	if err != nil {
		return 0, fmt.Errorf("ping failed (exit code %v). Output: %s", err, output)
	}
	return 0, fmt.Errorf("could not parse average latency from ping output: %s", output)
}

func main() {
	// Configuration
	targetHost := "8.8.8.8"
	pingCount := 4

	fmt.Printf("Measuring latency to %s using %d attempts...\n", targetHost, pingCount)

	avgLatency, err := MeasureLatency(targetHost, pingCount)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}

	fmt.Printf("Successfully measured latency.\n")
	fmt.Printf("Target Host:     %s\n", targetHost)
	fmt.Printf("Ping Count:      %d\n", pingCount)
	fmt.Printf("Average Latency: %.3f ms\n", avgLatency)
}

