// MeasureLatency pings a specified host a user-defined number of times
// and returns the average latency in milliseconds.
// It uses the system's 'ping' command via the os/exec package.
func MeasureLatency(host string, count int) (float64, error) {
	var cmd *exec.Cmd

	// Configure the ping command based on the operating system
	if runtime.GOOS == "windows" {
		// Windows uses -n for count
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		// Linux and macOS use -c for count
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	// Execute the command and capture the output
	out, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping execution failed: %w (output: %s)", err, string(out))
	}

	output := string(out)

	if runtime.GOOS == "windows" {
		// Windows typical output line: "Average = 14ms"
		re := regexp.MustCompile(`Average = (\d+)ms`)
		matches := re.FindStringSubmatch(output)
		if len(matches) > 1 {
			avg, err := strconv.ParseFloat(matches[1], 64)
			if err != nil {
				return 0, fmt.Errorf("failed to parse Windows average latency: %w", err)
			}
			return avg, nil
		}
	} else {
		// Unix-like (Linux/macOS) typical output line:
		// "rtt min/avg/max/mdev = 13.432/14.567/15.201/0.789 ms"
		// or "round-trip min/avg/max/stddev = 13.432/14.567/15.201/0.789 ms"
		lines := strings.Split(output, "\n")
		for _, line := range lines {
			if strings.Contains(line, "min/avg/max") {
				// Regex to capture the second value in the slash-separated list (the average)
				re := regexp.MustCompile(`= [0-9.]+/([0-9.]+)/[0-9.]+/[0-9.]+`)
				matches := re.FindStringSubmatch(line)
				if len(matches) > 1 {
					avg, err := strconv.ParseFloat(matches[1], 64)
					if err != nil {
						return 0, fmt.Errorf("failed to parse Unix average latency: %w", err)
					}
					return avg, nil
				}
			}
		}
	}

	return 0, fmt.Errorf("could not find average latency in ping output")
}

func main() {
	// Configuration
	targetHost := "8.8.8.8"
	pingCount := 4

	fmt.Printf("Measuring latency to %s (%d attempts)...\n", targetHost, pingCount)

