package main

import (
	"errors"
	"fmt"
	"os/exec"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Execute the ping command.
	// -c specifies the number of packets to send (standard on Linux and macOS).
	// Arguments are passed directly to exec.Command to prevent shell injection vulnerabilities.
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w (output: %s)", err, strings.TrimSpace(string(output)))
	}

	// Parse the output to find the RTT statistics line.
	// Typical Linux output: rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
	// Typical macOS output: round-trip min/avg/max/stddev = 12.345/23.456/34.567/5.678 ms
	outputStr := string(output)
	lines := strings.Split(outputStr, "\n")
	for _, line := range lines {
		// Most Unix-like ping versions include "min/avg/max" in the summary line.
		if strings.Contains(line, "min/avg/max") {
			// Split by '=' to separate the label (left) from the numeric values (right).
			parts := strings.Split(line, "=")
			if len(parts) < 2 {
				continue
			}

			// Clean the values part (e.g., " 12.345/23.456/34.567/5.678 ms")
			// strings.Fields splits by whitespace, giving us ["12.345/23.456/34.567/5.678", "ms"]
			valFields := strings.Fields(parts[1])
			if len(valFields) == 0 {
				continue
			}

			// Split the metrics by '/' to isolate the average.
			// The format is consistently min/avg/max/...
			metrics := strings.Split(valFields[0], "/")
			if len(metrics) < 2 {
				return 0, errors.New("failed to parse RTT metrics from ping output")
			}

			// The average RTT is the second value in the slash-separated sequence.
			avg, err := strconv.ParseFloat(metrics[1], 64)
			if err != nil {
				return 0, fmt.Errorf("invalid average latency value '%s': %w", metrics[1], err)
			}

			return avg, nil
		}
	}

	return 0, errors.New("could not find RTT statistics in ping output")
}

func main() {
	// Example usage:
	host := "8.8.8.8"
	count := 3
	fmt.Printf("Pinging %s %d times...\n", host, count)

	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}

	fmt.Printf("Average Latency: %.3f ms\n", avg)
}

