package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}

	// Security Fix: Prevent argument injection.
	// Even when using exec.Command correctly, some binaries interpret strings starting with '-' as flags.
	if strings.HasPrefix(host, "-") {
		return 0, errors.New("invalid host: host cannot start with '-'")
	}

	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Security Fix: Avoid shell execution.
	// We pass arguments directly to exec.Command instead of using "bash -c".
	// This prevents command injection vulnerabilities as the shell is not involved in parsing the arguments.
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w (output: %s)", err, string(output))
	}

	outputStr := string(output)

	// Regex to extract the average RTT from the ping output.
	// This handles standard output formats for Linux (rtt min/avg/max/mdev)
	// and macOS (round-trip min/avg/max/stddev).
	// The regex captures the second value (average) in the "min/avg/max/xxx = v1/v2/v3/v4" format.
	re := regexp.MustCompile(`min/avg/max/.*? = [^/]+/([0-9.]+)/`)
	matches := re.FindStringSubmatch(outputStr)
	if len(matches) < 2 {
		return 0, errors.New("failed to parse average latency from ping output")
	}

	avgStr := matches[1]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}

	return avg, nil
}

func main() {
	// Example usage
	host := "8.8.8.8"
	count := 3
	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency for %s: %v\n", host, err)
		return
	}
	fmt.Printf("Average latency for %s over %d attempts: %.3f ms\n", host, count, avg)
}

