package main

import (
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
)

// MeasureLatency pings a specified host a user-defined number of times
// and returns the average latency in milliseconds.
// It utilizes the system's native 'ping' utility via the os/exec package.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("ping count must be greater than 0")
	}

	var cmd *exec.Cmd
	// The ping command flags differ between Windows and Unix-based systems.
	if runtime.GOOS == "windows" {
		// Windows uses -n for the number of echo requests to send.
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		// Linux and macOS use -c for the count of packets.
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	// Capture both stdout and stderr to handle error messages from the ping utility.
	out, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping execution failed: %w (output: %s)", err, string(out))
	}

	output := string(out)

	if runtime.GOOS == "windows" {
		// Windows output typically contains a summary line like: "Average = 15ms"
		// We use a regular expression to extract the numeric value.
		re := regexp.MustCompile(`Average\s*=\s*(\d+)ms`)
		matches := re.FindStringSubmatch(output)
		if len(matches) >= 2 {
			avg, parseErr := strconv.ParseFloat(matches[1], 64)
			if parseErr != nil {
				return 0, fmt.Errorf("failed to parse Windows latency value: %w", parseErr)
			}
			return avg, nil
		}
	} else {
		// Unix-like systems (Linux/macOS) typically output a summary line like:
		// "rtt min/avg/max/mdev = 10.123/12.456/15.789/1.234 ms"
		// We look for the slash-separated values following the '=' sign.
		re := regexp.MustCompile(`=\s*([\d\.]+)/([\d\.]+)/([\d\.]+)`)
		matches := re.FindStringSubmatch(output)
		if len(matches) >= 3 {
			// index 1 is min, index 2 is avg, index 3 is max.
			avg, parseErr := strconv.ParseFloat(matches[2], 64)
			if parseErr != nil {
				return 0, fmt.Errorf("failed to parse Unix latency value: %w", parseErr)
			}
			return avg, nil
		}
	}

	return 0, fmt.Errorf("could not find average latency in ping output")
}

func main() {
	// Configuration
	host := "8.8.8.8"
	count := 4

	fmt.Printf("Measuring latency to %s with %d attempts...\n", host, count)

	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}

	fmt.Printf("Average Latency: %.3f ms\n", avg)
}

