package main

import (
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
)

// MeasureLatency pings a specified host a user-defined number of times 
// and returns the average latency in milliseconds.
// It uses the system's 'ping' command via the os/exec package.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("ping count must be greater than 0")
	}

	var cmd *exec.Cmd
	// Determine OS to set the correct ping flags
	// Linux/macOS use -c for count, Windows uses -n
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	// Execute the command and capture combined stdout and stderr
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping execution failed: %w (output: %s)", err, string(output))
	}

	return parseAverageLatency(string(output))
}

// parseAverageLatency extracts the average RTT from the ping command output.
func parseAverageLatency(output string) (float64, error) {
	// Unix-like output usually contains a summary line:
	// rtt min/avg/max/mdev = 14.123/15.456/16.789/0.500 ms
	// We look for the pattern of four numbers separated by slashes.
	unixRe := regexp.MustCompile(`([0-9.]+)/([0-9.]+)/([0-9.]+)/([0-9.]+)`)
	if matches := unixRe.FindStringSubmatch(output); len(matches) >= 3 {
		// matches[2] is the 'avg' value
		return strconv.ParseFloat(matches[2], 64)
	}

	// Windows output usually contains:
	// Minimum = 14ms, Maximum = 16ms, Average = 15ms
	winRe := regexp.MustCompile(`Average\s*=\s*([0-9]+)\s*ms`)
	if matches := winRe.FindStringSubmatch(output); len(matches) >= 2 {
		return strconv.ParseFloat(matches[1], 64)
	}

	return 0, fmt.Errorf("could not parse average latency from output: %s", output)
}

func main() {
	// Configuration
	targetHost := "8.8.8.8"
	pingCount := 4

	fmt.Printf("Measuring latency to %s (%d attempts)...\n", targetHost, pingCount)

	avgLatency, err := MeasureLatency(targetHost, pingCount)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}

	fmt.Printf("Average Latency: %.3f ms\n", avgLatency)
}

