package main

import (
	"errors"
	"fmt"
	"os/exec"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Execute the ping command directly. 
	// Using exec.Command with separate arguments is safer than using bash -c, 
	// as it avoids shell injection vulnerabilities.
	// The '-c' flag is standard for count on Linux and macOS.
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w (output: %s)", err, string(output))
	}

	// Parse the output to find the statistics line.
	// We look for the line containing "min/avg/max", which is standard across most Unix-like ping versions.
	outputStr := string(output)
	lines := strings.Split(outputStr, "\n")
	var statsLine string
	for _, line := range lines {
		if strings.Contains(line, "min/avg/max") {
			statsLine = line
			break
		}
	}

	if statsLine == "" {
		return 0, errors.New("could not find RTT statistics in ping output (host might be unreachable)")
	}

	// Standard ping output formats:
	// Linux: rtt min/avg/max/mdev = 10.111/11.222/12.333/0.444 ms
	// macOS: round-trip min/avg/max/stddev = 10.111/11.222/12.333/0.444 ms
	// BusyBox: round-trip min/avg/max = 10.111/11.222/12.333 ms

	// 1. Split by '=' to isolate the values from the labels.
	parts := strings.Split(statsLine, "=")
	if len(parts) < 2 {
		return 0, fmt.Errorf("unexpected statistics format: %s", statsLine)
	}

	// 2. Extract the numeric values. 
	// strings.Fields handles whitespace and separates the slash-delimited numbers from "ms".
	fields := strings.Fields(parts[1])
	if len(fields) == 0 {
		return 0, fmt.Errorf("no values found in statistics line: %s", statsLine)
	}

	// 3. Split the slash-separated values (min/avg/max/...).
	nums := strings.Split(fields[0], "/")
	if len(nums) < 2 {
		return 0, fmt.Errorf("could not parse average latency from values: %s", fields[0])
	}

	// The average is the second value in the sequence.
	avgStr := nums[1]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency '%s' to float: %w", avgStr, err)
	}

	return avg, nil
}

func main() {
	// Example usage:
	host := "8.8.8.8"
	count := 3

	fmt.Printf("Measuring latency to %s with %d attempts...\n", host, count)
	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}

	fmt.Printf("Average Latency: %.3f ms\n", avg)
}

