// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec safely and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Security: Validate the host to prevent argument injection (e.g., host starting with "-")
	// and to ensure it only contains characters valid for an IP address or hostname.
	if !isSafeHost(host) {
		return 0, errors.New("invalid host: contains unsafe characters or is improperly formatted")
	}

	// Security: Execute the 'ping' command directly without using a shell (no 'bash -c').
	// Arguments are passed as separate strings to the exec.Command function, 
	// which prevents shell injection vulnerabilities.
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, string(output))
	}

	// Parse the output to find the line containing RTT statistics.
	// Standard ping outputs (iputils or BSD/macOS) usually contain "min/avg/max".
	outputStr := string(output)
	var statsLine string
	for _, line := range strings.Split(outputStr, "\n") {
		if strings.Contains(line, "min/avg/max") {
			statsLine = line
			break
		}
	}

	if statsLine == "" {
		return 0, errors.New("could not find RTT statistics in ping output")
	}

	// Extract average latency using a robust regex.
	// Example line: rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
	// The average is the second value in the slash-separated sequence.
	re := regexp.MustCompile(`= ([0-9.]+)/([0-9.]+)/([0-9.]+)/([0-9.]+)`)
	matches := re.FindStringSubmatch(statsLine)
	if len(matches) < 3 {
		return 0, errors.New("failed to parse average latency from ping output")
	}

	// matches[1] is min, matches[2] is avg
	avgStr := matches[2]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}

	return avg, nil
}

// isSafeHost validates that the input string is a valid IP address or a safe hostname.
// This prevents attackers from passing command flags or shell metacharacters.
func isSafeHost(host string) bool {
	if len(host) == 0 || len(host) > 253 {
		return false
	}

	// Check if it's a valid IP address (IPv4 or IPv6)
	if net.ParseIP(host) != nil {
		return true
	}

	// For hostnames, ensure it doesn't start with a hyphen (argument injection defense)
	// and contains only alphanumeric characters, dots, and hyphens.
	if host[0] == '-' {
		return false
	}

	for _, r := range host {
		if !((r >= 'a' && r <= 'z') || (r >= 'A' && r <= 'Z') || (r >= '0' && r <= '9') || r == '.' || r == '-' || r == ':') {
			return false
		}
	}

	return true
}

func main() {
	// Example usage:
	host := "8.8.8.8"
	count := 3
	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}
	fmt.Printf("Average latency for %s: %.3f ms\n", host, avg)
