// MeasureLatency pings a specified host a user-defined number of times 
// and returns the average latency in milliseconds.
// It uses the system's 'ping' command via the os/exec package.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("ping count must be greater than 0")
	}

	var cmd *exec.Cmd
	// Determine the operating system to set the correct ping flags
	// -c is used for count on Unix-like systems (Linux, macOS)
	// -n is used for count on Windows
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	// Execute the command and capture the combined stdout and stderr
	out, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping execution failed: %w (output: %s)", err, string(out))
	}

	output := string(out)
	return parseAverageLatency(output)
}

// parseAverageLatency extracts the average RTT from the ping command output.
func parseAverageLatency(output string) (float64, error) {
	if runtime.GOOS == "windows" {
		// Windows output example: "Average = 14ms"
		re := regexp.MustCompile(`Average = (\d+)ms`)
		matches := re.FindStringSubmatch(output)
		if len(matches) >= 2 {
			return strconv.ParseFloat(matches[1], 64)
		}
	} else {
		// Unix-like output example: "rtt min/avg/max/mdev = 14.123/15.456/16.789/0.555 ms"
		// The second value in the slash-separated list is the average.
		re := regexp.MustCompile(`([\d.]+)/([\d.]+)/([\d.]+)/([\d.]+) ms`)
		matches := re.FindStringSubmatch(output)
		if len(matches) >= 3 {
			// matches[1] is min, matches[2] is avg
			return strconv.ParseFloat(matches[2], 64)
		}

		// Fallback for some versions of ping that might have different labels
		reAlt := regexp.MustCompile(`avg = ([\d.]+)`)
		matchesAlt := reAlt.FindStringSubmatch(output)
		if len(matchesAlt) >= 2 {
			return strconv.ParseFloat(matchesAlt[1], 64)
		}
	}

	return 0, fmt.Errorf("could not parse average latency from output: %s", strings.TrimSpace(output))
}

func main() {
	// Configuration
	targetHost := "8.8.8.8"
	pingCount := 4

