// MeasureLatency pings a specified host a user-defined number of times
// and returns the average latency in milliseconds.
// It uses the system's 'ping' command via the os/exec package.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("ping count must be a positive integer")
	}

	var cmd *exec.Cmd
	// Configure the ping command based on the operating system.
	// Windows uses '-n' for count, while Unix-like systems (Linux, macOS) use '-c'.
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	// Execute the command and capture the combined output of stdout and stderr.
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w (output: %s)", err, string(output))
	}

	return parseAverageLatency(string(output))
}

// parseAverageLatency extracts the average RTT (round-trip time) from the ping output.
func parseAverageLatency(output string) (float64, error) {
	var re *regexp.Regexp
	var matchIndex int

	if runtime.GOOS == "windows" {
		// Windows typical output: "Minimum = 14ms, Maximum = 16ms, Average = 15ms"
		re = regexp.MustCompile(`Average = (\d+)ms`)
		matchIndex = 1
	} else {
		// Unix-like typical output: "rtt min/avg/max/mdev = 14.123/15.456/16.789/0.500 ms"
		// We capture the sequence of numbers separated by slashes.
		re = regexp.MustCompile(`([0-9.]+)/([0-9.]+)/([0-9.]+)`)
		matchIndex = 2 // The second group in the sequence is 'avg'.
	}

	matches := re.FindStringSubmatch(output)
	if len(matches) <= matchIndex {
		return 0, fmt.Errorf("could not parse average latency from ping output")
	}

	// Convert the captured string value to a float64.
	avg, err := strconv.ParseFloat(matches[matchIndex], 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert latency value '%s' to float: %w", matches[matchIndex], err)
	}

	return avg, nil
}

func main() {
	// Configuration
	targetHost := "8.8.8.8"
	pingCount := 4

	fmt.Printf("Starting latency measurement for %s (%d attempts)...\n", targetHost, pingCount)

	avg, err := MeasureLatency(targetHost, pingCount)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}

	fmt.Printf("Measurement successful.\n")
	fmt.Printf("Target Host:    %s\n", targetHost)
	fmt.Printf("Average Latency: %.3f ms\n", avg)
}

