package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
// Note: This implementation is designed for Unix-like systems (Linux, macOS).
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Execute the ping command directly. Direct execution is safer than using a shell wrapper.
	// The -c flag specifies the number of packets to send (standard on Linux and macOS).
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		// ping returns a non-zero exit code if the host is unreachable or packets are lost.
		return 0, fmt.Errorf("ping command failed: %w (output: %s)", err, string(output))
	}

	outputStr := string(output)

	// Regex to extract RTT statistics (min/avg/max/mdev).
	// This pattern is designed to be robust across different Unix-like ping versions.
	// Example Linux: rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
	// Example macOS: round-trip min/avg/max/stddev = 12.345/23.456/34.567/5.678 ms
	re := regexp.MustCompile(`(?:rtt|round-trip) min/avg/max/(?:mdev|stddev)\s*=\s*([0-9.]+)/([0-9.]+)/([0-9.]+)/([0-9.]+)`)
	matches := re.FindStringSubmatch(outputStr)

	// matches[0] is the full match, matches[1] is min, matches[2] is avg, etc.
	if len(matches) < 3 {
		return 0, errors.New("could not parse average RTT from ping output")
	}

	// Extract the average latency value (the second captured group).
	avgStr := matches[2]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}

	return avg, nil
}

func main() {
	// Example usage of the MeasureLatency function.
	host := "8.8.8.8"
	count := 3

	fmt.Printf("Measuring latency to %s (%d attempts)...\n", host, count)
	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}

	fmt.Printf("Average Latency: %.3f ms\n", avg)
}

