package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// SECURITY FIX: Prevent Argument Injection.
	// If the host starts with a hyphen, it could be interpreted as a command-line flag.
	if strings.HasPrefix(host, "-") {
		return 0, errors.New("invalid host: host cannot start with a hyphen")
	}

	// SECURITY FIX: Prevent Command Injection.
	// Instead of using exec.Command("bash", "-c", ...), we call the 'ping' binary directly.
	// This ensures that arguments are passed as a slice of strings, preventing the shell 
	// from interpreting meta-characters like ';', '&', or '|'.
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, string(output))
	}

	outputStr := string(output)

	// Regex to extract average latency from the RTT statistics line.
	// This regex is designed to work with common Linux (rtt min/avg/max/mdev) 
	// and macOS (round-trip min/avg/max/stddev) output formats.
	// Format: min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
	re := regexp.MustCompile(`(?:rtt|round-trip) min/avg/max/(?:mdev|stddev) = [0-9.]+/([0-9.]+)/[0-9.]+/[0-9.]+ ms`)
	matches := re.FindStringSubmatch(outputStr)
	if len(matches) < 2 {
		return 0, errors.New("failed to parse average latency from ping output")
	}

	avgStr := matches[1]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}

	return avg, nil
}

func main() {
	// Example usage:
	host := "8.8.8.8"
	count := 3
	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}
	fmt.Printf("Average latency for %s: %.3f ms\n", host, avg)
}

