package main

import (
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
)

// MeasureLatency pings a specified host a user-defined number of times 
// and returns the average latency in milliseconds.
// It uses the system's 'ping' command via the os/exec package.
func MeasureLatency(host string, count int) (float64, error) {
	var cmd *exec.Cmd
	countStr := strconv.Itoa(count)

	// Determine command arguments based on the operating system
	if runtime.GOOS == "windows" {
		// Windows uses -n for count
		cmd = exec.Command("ping", "-n", countStr, host)
	} else {
		// Linux and macOS use -c for count
		cmd = exec.Command("ping", "-c", countStr, host)
	}

	// Execute the command and capture the output
	out, err := cmd.Output()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w", err)
	}

	output := string(out)

	// Parse the output based on common ping formats
	// Unix-like (Linux/macOS) format: min/avg/max/mdev = 10.123/12.456/15.789/1.234 ms
	unixRegex := regexp.MustCompile(`([0-9.]+)/([0-9.]+)/([0-9.]+)/([0-9.]+)`)
	unixMatches := unixRegex.FindStringSubmatch(output)
	if len(unixMatches) >= 3 {
		// Index 2 is the 'avg' value
		avg, err := strconv.ParseFloat(unixMatches[2], 64)
		if err == nil {
			return avg, nil
		}
	}

	// Windows format: Average = 12ms
	winRegex := regexp.MustCompile(`Average = (\d+)ms`)
	winMatches := winRegex.FindStringSubmatch(output)
	if len(winMatches) >= 2 {
		avg, err := strconv.ParseFloat(winMatches[1], 64)
		if err == nil {
			return avg, nil
		}
	}

	return 0, fmt.Errorf("could not parse average latency from ping output")
}

func main() {
	host := "google.com"
	count := 3

	fmt.Printf("Measuring latency to %s (%d attempts)...\n", host, count)
	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}

	fmt.Printf("Average Latency: %.3f ms\n", avg)
}

