func parseAvgLatency(output string) (float64, error) {
	scanner := bufio.NewScanner(strings.NewReader(output))
	for scanner.Scan() {
		line := scanner.Text()

		// Unix-like output parsing (Linux/macOS)
		// Example: rtt min/avg/max/mdev = 24.107/24.532/25.101/0.412 ms
		// Example: round-trip min/avg/max/stddev = 24.107/24.532/25.101/0.412 ms
		if strings.Contains(line, "rtt") || strings.Contains(line, "round-trip") {
