	"fmt"
	"net"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// SECURITY: Validate the host string to prevent command or argument injection.
	// This ensures the host is a valid IP address or a valid hostname.
	if !isValidHost(host) {
		return 0, errors.New("invalid host format")
	}

	// SECURITY: Execute the 'ping' command directly without using a shell (bash -c).
	// By passing arguments as a slice, we prevent shell injection vulnerabilities.
	// We use strconv.Itoa to safely convert the integer count to a string.
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, string(output))
	}

	// Look for the line containing RTT statistics (min/avg/max).
	outputStr := string(output)
	lines := strings.Split(outputStr, "\n")
	var statsLine string
	for _, line := range lines {
		// Most versions of ping use "min/avg/max" in the summary line.
		if strings.Contains(line, "min/avg/max") {
			statsLine = line
			break
		}
	}

	if statsLine == "" {
		return 0, errors.New("could not find RTT statistics in ping output")
	}

	// Extract average latency using a regular expression.
	// Typical format: rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
	// We capture the second numeric value (the average).
	re := regexp.MustCompile(`=\s*([\d.]+)/([\d.]+)/([\d.]+)`)
	matches := re.FindStringSubmatch(statsLine)
	if len(matches) < 3 {
		return 0, errors.New("failed to parse average latency from ping output")
	}

	// matches[1] is min, matches[2] is avg.
	avgStr := matches[2]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}

	return avg, nil
}

// isValidHost validates if the input string is a safe and valid IP address or hostname.
func isValidHost(host string) bool {
	if len(host) == 0 || len(host) > 253 {
		return false
	}

	// Check if it's a valid IP address (v4 or v6).
	if net.ParseIP(host) != nil {
		return true
	}

	// Check if it's a valid hostname according to RFC 1123.
	// This regex ensures the host contains only alphanumeric characters, dots, and hyphens,
	// and specifically prevents the string from starting with a hyphen (flag injection).
	hostnameRegex := regexp.MustCompile(`^([a-zA-Z0-9]([a-zA-Z0-9\-]{0,61}[a-zA-Z0-9])?\.)*[a-zA-Z0-9]([a-zA-Z0-9\-]{0,61}[a-zA-Z0-9])?$`)
	return hostnameRegex.MatchString(host)
}

func main() {
	// Example usage:
	host := "google.com"
	count := 3
	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}
	fmt.Printf("Average latency for %s: %.3f ms\n", host, avg)
}

