// It utilizes the system's native ping command via the os/exec package.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("ping count must be greater than zero")
	}

	var cmd *exec.Cmd
	countStr := strconv.Itoa(count)

	// Configure the command based on the operating system.
	// Unix-like systems (Linux/macOS) typically use '-c' for count.
	// Windows uses '-n' for count.
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", countStr, host)
	} else {
		cmd = exec.Command("ping", "-c", countStr, host)
	}

	// Capture both stdout and stderr to handle error reporting properly.
	out, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w (output: %s)", err, string(out))
	}

	output := string(out)

	// Regex patterns to parse the average latency from the ping summary.

	// Unix-like pattern (Linux/macOS):
	// Matches summary line like: "rtt min/avg/max/mdev = 10.123/12.456/15.789/1.234 ms"
	// We capture the second group (avg).
	unixRegex := regexp.MustCompile(`min/avg/max/.*?=\s*[0-9.]+/([0-9.]+)/[0-9.]+`)

	// Windows pattern:
