	winRegex := regexp.MustCompile(`Average\s*=\s*([0-9.]+)\s*ms`)

	// Check for Unix-style output first
	if matches := unixRegex.FindStringSubmatch(output); len(matches) > 1 {
		return strconv.ParseFloat(matches[1], 64)
	}

	// Check for Windows-style output
	if matches := winRegex.FindStringSubmatch(output); len(matches) > 1 {
		return strconv.ParseFloat(matches[1], 64)
	}

	return 0, fmt.Errorf("failed to parse average latency from ping output")
}

func main() {
	// Example configuration
	targetHost := "8.8.8.8"
	attempts := 4

	fmt.Printf("Starting latency measurement for %s (%d attempts)...\n", targetHost, attempts)

	avgLatency, err := MeasureLatency(targetHost, attempts)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}

	fmt.Printf("Measurement Complete.\n")
	fmt.Printf("Target: %s\n", targetHost)
	fmt.Printf("Average Latency: %.3f ms\n", avgLatency)
