// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via the os/exec package and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Execute the ping command directly rather than through a shell to prevent command injection
	// and avoid unnecessary shell overhead. The '-c' flag is standard for packet count on Unix-like systems.
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping execution failed: %w (output: %s)", err, string(output))
	}

	outputStr := string(output)
	lines := strings.Split(outputStr, "\n")

	// The summary line in ping output typically contains "min/avg/max".
	// Linux: rtt min/avg/max/mdev = 13.085/13.250/13.415/0.134 ms
	// macOS: round-trip min/avg/max/stddev = 13.085/13.250/13.415/0.134 ms
	var statsLine string
	for _, line := range lines {
		if strings.Contains(line, "min/avg/max") {
			statsLine = line
			break
		}
	}

	if statsLine == "" {
		return 0, errors.New("could not find RTT statistics in ping output")
	}

	// Regex to extract the values after the '=' sign. 
	// We capture groups of digits and dots separated by forward slashes.
	re := regexp.MustCompile(`=\s*([\d.]+)/([\d.]+)/([\d.]+)/([\d.]+)`)
	matches := re.FindStringSubmatch(statsLine)

	// matches[0] is the full match, [1] is min, [2] is avg, [3] is max, [4] is mdev/stddev
	if len(matches) < 3 {
		return 0, errors.New("failed to parse average latency from ping output")
	}

	avgStr := matches[2]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency '%s' to float: %w", avgStr, err)
	}

	return avg, nil
}

func main() {
	// Configuration
	targetHost := "8.8.8.8"
	pingCount := 4

	fmt.Printf("Measuring latency to %s (%d attempts)...\n", targetHost, pingCount)

	avg, err := MeasureLatency(targetHost, pingCount)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}

	fmt.Printf("Average Latency: %.3f ms\n", avg)
}

