		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		// Linux/macOS: ping -c <count> <host>
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	// Capture the output of the ping command
	out, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w (output: %s)", err, string(out))
	}

	output := string(out)
	return parseAverageLatency(output)
}

// parseAverageLatency extracts the average RTT from the ping command output.
func parseAverageLatency(output string) (float64, error) {
	var avgStr string

	if runtime.GOOS == "windows" {
		// Windows output example: "Average = 15ms"
		re := regexp.MustCompile(`Average = (\d+)\s*ms`)
		matches := re.FindStringSubmatch(output)
		if len(matches) < 2 {
			return 0, errors.New("could not parse average latency from Windows output")
		}
		avgStr = matches[1]
	} else {
