		// We look for the summary line and take the second value in the slash-separated list.
		re := regexp.MustCompile(`= [\d\.]+/([\d\.]+)/[\d\.]+/[\d\.]+`)
		matches := re.FindStringSubmatch(output)
		if len(matches) < 2 {
