			}
		}
		avgStr = matches[1]
	}

	// Convert the extracted string to float64
	avg, err := strconv.ParseFloat(strings.TrimSpace(avgStr), 64)
	if err != nil {
		return 0, fmt.Errorf("failed to parse latency value '%s': %w", avgStr, err)
	}

	return avg, nil
}

