package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Use exec.Command directly instead of wrapping in bash -c to prevent shell injection 
	// and to handle arguments correctly.
	// Note: -c is the count flag for Linux and macOS. 
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w (output: %s)", err, string(output))
	}

	outputStr := string(output)

	// Regex to capture RTT statistics.
	// This regex is designed to be compatible with both Linux (iputils) and macOS (BSD) ping outputs.
	// Linux: rtt min/avg/max/mdev = 0.060/0.121/0.201/0.057 ms
	// macOS: round-trip min/avg/max/stddev = 0.060/0.121/0.201/0.057 ms
	// It captures the numbers in the format min/avg/max.
	re := regexp.MustCompile(`(?i)(?:rtt|round-trip) min/avg/max(?:/mdev|/stddev)?\s*=\s*([0-9.]+)/([0-9.]+)/([0-9.]+)`)
	matches := re.FindStringSubmatch(outputStr)

	// matches[0] is the full string, matches[1] is min, matches[2] is avg, matches[3] is max.
	if len(matches) < 3 {
		return 0, errors.New("could not find or parse RTT statistics in ping output")
	}

	avgStr := matches[2]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency '%s' to float: %w", avgStr, err)
	}

	return avg, nil
}

func main() {
	// Example usage
	host := "8.8.8.8"
	count := 3
	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}
	fmt.Printf("Average latency for %s over %d attempts: %.3f ms\n", host, count, avg)
}

