import (
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
)

// MeasureLatency pings a specified host a user-defined number of times
// and returns the average latency in milliseconds.
// It utilizes the os/exec package to invoke the system's native ping utility.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be greater than zero")
	}

	var cmd *exec.Cmd
	// Configure the ping command based on the operating system.
	// Windows uses '-n' for the count, while Unix-like systems (Linux, macOS) use '-c'.
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	// CombinedOutput runs the command and returns its combined standard output and standard error.
	out, err := cmd.CombinedOutput()
	output := string(out)
	if err != nil {
		return 0, fmt.Errorf("ping execution failed: %w (output: %s)", err, output)
	}

	var avg float64
	if runtime.GOOS == "windows" {
		// Windows typical output: "Minimum = 14ms, Maximum = 16ms, Average = 15ms"
		re := regexp.MustCompile(`Average = (\d+)ms`)
		matches := re.FindStringSubmatch(output)
		if len(matches) < 2 {
			return 0, fmt.Errorf("failed to parse average latency from Windows ping output")
		}
		avg, err = strconv.ParseFloat(matches[1], 64)
	} else {
		// Unix typical output: "rtt min/avg/max/mdev = 14.123/15.567/16.987/1.123 ms"
		// This regex targets the summary line and captures the second value (the average).
		re := regexp.MustCompile(`min/avg/max/.*?=\s*[\d.]+/([\d.]+)`)
		matches := re.FindStringSubmatch(output)
		if len(matches) < 2 {
			// Fallback for different ping versions (e.g., BusyBox)
			reFallback := regexp.MustCompile(`=\s*[\d.]+/([\d.]+)`)
			matches = reFallback.FindStringSubmatch(output)
			if len(matches) < 2 {
				return 0, fmt.Errorf("failed to parse average latency from Unix ping output")
			}
		}
		avg, err = strconv.ParseFloat(matches[1], 64)
	}

	if err != nil {
		return 0, fmt.Errorf("failed to convert latency string to float: %w", err)
	}

	return avg, nil
}

func main() {
	// Configuration
	targetHost := "8.8.8.8"
	pingCount := 4

	fmt.Printf("Measuring latency to %s with %d attempts...\n", targetHost, pingCount)

	avgLatency, err := MeasureLatency(targetHost, pingCount)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}

	fmt.Printf("Success! Average Latency: %.3f ms\n", avgLatency)
}

