		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		// Linux and macOS use -c for count
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	// Run the command and capture the output
	out, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping execution failed: %w (output: %s)", err, string(out))
	}

	return parseAverageLatency(string(out))
}

// parseAverageLatency extracts the average RTT from the ping command output using regex.
func parseAverageLatency(output string) (float64, error) {
	var avgStr string

	if runtime.GOOS == "windows" {
		// Windows output format: ... Average = 25ms
		re := regexp.MustCompile(`Average = (\d+)ms`)
		matches := re.FindStringSubmatch(output)
		if len(matches) > 1 {
			avgStr = matches[1]
		}
	} else {
