		// rtt min/avg/max/mdev = 14.640/14.711/14.814/0.074 ms
		// round-trip min/avg/max/stddev = 14.640/14.711/14.814/0.074 ms
		re := regexp.MustCompile(`min/avg/max/(?:mdev|stddev) = [0-9.]+/([0-9.]+)/[0-9.]+/[0-9.]+ ms`)
		matches := re.FindStringSubmatch(output)
		if len(matches) > 1 {
			avgStr = matches[1]
		}
	}

	if avgStr == "" {
		return 0, fmt.Errorf("could not parse average latency from ping output")
	}

	// Convert the extracted string to float64
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to parse latency value: %w", err)
	}

	return avg, nil
}

func main() {
	host := "google.com"
	count := 3

	fmt.Printf("Measuring latency to %s (%d attempts)...\n", host, count)
	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}

	fmt.Printf("Average Latency: %.3f ms\n", avg)
